import { useLocation, useNavigate } from "react-router-dom";
import { useState, useMemo } from "react";
import logo from "../assets/logo.png";

export default function Checkout() {
  const location = useLocation();
  const navigate = useNavigate();

  const cart = Array.isArray(location.state?.cart) ? location.state.cart : [];

  const [form, setForm] = useState({
    name: "",
    email: "",
    address: "",
    cardHolder: "",
    cardType: "visa",
    cardNumber: "",
    cvv: "",
    expiry: "",
  });

  const total = useMemo(() => {
    return cart.reduce((sum, item) => {
      const price = Number(item?.price || 0);
      const qty = Number(item?.qty || 0);
      return sum + price * qty;
    }, 0);
  }, [cart]);

  const handleChange = (e) => {
    setForm((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = () => {
    console.log("COMPRA:", {
      customer: form,
      cart,
      total,
    });

    alert("Compra realizada");
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <div style={styles.layout}>
          <div style={styles.cartSection}>
            <div style={styles.logoBox}>
              <img src={logo} alt="logo" style={styles.logo} />
              <h2>Checkout</h2>
            </div>

            {cart.length === 0 ? (
              <div style={styles.empty}>
                <p>No hay productos en el carrito.</p>
                <button
                  style={styles.button}
                  onClick={() => navigate("/tienda")}
                >
                  Volver a la tienda
                </button>
              </div>
            ) : (
              <>
                <div style={styles.cartList}>
                  {cart.map((item, index) => (
                    <div key={item.id || index} style={styles.cartItem}>
                      <span>
                        {item.name || "Producto"} x {item.qty || 1}
                      </span>
                      <span>
                        $
                        {(
                          Number(item.price || 0) * Number(item.qty || 0)
                        ).toFixed(2)}
                      </span>
                    </div>
                  ))}
                </div>

                <h3 style={styles.total}>Total: ${total.toFixed(2)}</h3>
              </>
            )}
          </div>

          {cart.length > 0 && (
            <div style={styles.formSection}>
              <input
                name="name"
                placeholder="Nombre"
                value={form.name}
                onChange={handleChange}
                style={styles.input}
              />
              <input
                name="email"
                placeholder="Email"
                value={form.email}
                onChange={handleChange}
                style={styles.input}
              />
              <input
                name="address"
                placeholder="Dirección"
                value={form.address}
                onChange={handleChange}
                style={styles.input}
              />

              <h4 style={styles.subtitle}>Datos de tarjeta</h4>

              <input
                name="cardHolder"
                placeholder="Titular"
                value={form.cardHolder}
                onChange={handleChange}
                style={styles.input}
              />

              <select
                name="cardType"
                value={form.cardType}
                onChange={handleChange}
                style={styles.input}
              >
                <option value="visa">Visa</option>
                <option value="mastercard">MasterCard</option>
                <option value="amex">American Express</option>
              </select>

              <input
                name="cardNumber"
                placeholder="Número de tarjeta"
                value={form.cardNumber}
                onChange={handleChange}
                style={styles.input}
              />
              <input
                name="cvv"
                placeholder="CVV"
                value={form.cvv}
                onChange={handleChange}
                style={styles.input}
              />
              <input
                name="expiry"
                placeholder="MM/AA"
                value={form.expiry}
                onChange={handleChange}
                style={styles.input}
              />

              <div style={styles.buttonRow}>
                <button onClick={handleSubmit} style={styles.primaryButton}>
                  Confirmar compra
                </button>

                <button
                  onClick={() => navigate("/tienda")}
                  style={styles.secondaryButton}
                >
                  Volver
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    backgroundColor: "#f5f7fb",
    padding: "2rem 1rem",
  },

  container: {
    maxWidth: "1100px",
    margin: "0 auto",
  },

  layout: {
    display: "flex",
    gap: "2rem",
    alignItems: "flex-start",
  },

  cartSection: {
    flex: 1,
    background: "white",
    padding: "1.5rem",
    borderRadius: "12px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.1)",
  },

  formSection: {
    flex: 1,
    background: "white",
    padding: "1.5rem",
    borderRadius: "12px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.1)",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
    position: "sticky",
    top: "20px",
  },

  logoBox: {
    textAlign: "center",
    marginBottom: "1rem",
  },

  logo: {
    width: "120px",
    marginBottom: "10px",
  },

  cartList: {
    maxHeight: "250px",
    overflowY: "auto",
    paddingRight: "5px",
    marginBottom: "1rem",
  },

  cartItem: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: "8px",
    fontSize: "0.95rem",
  },

  total: {
    marginTop: "1rem",
  },

  input: {
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #ddd",
    outline: "none",
  },

  buttonRow: {
    display: "flex",
    gap: "10px",
    marginTop: "1rem",
  },

  primaryButton: {
    flex: 1,
    padding: "10px",
    backgroundColor: "#32d5d5",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
  },

  secondaryButton: {
    flex: 1,
    padding: "10px",
    backgroundColor: "#e2e8f0",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
  },

  empty: {
    textAlign: "center",
    padding: "2rem",
  },

  subtitle: {
    marginTop: "1rem",
  },
};
